function(config){
  config = config || {};
  var limit = typeof config.limit === 'number' && isFinite(config.limit) ? Math.max(1, Math.floor(config.limit)) : 50;

  function normSpace(s){
    return (s || '').replace(/\u00a0/g,' ').replace(/[\t\r]+/g,' ').replace(/\n{3,}/g,'\n\n').replace(/ +/g,' ').trim();
  }
  function roleNorm(r){
    r = (r || '').toLowerCase();
    if (r === 'user' || r === 'assistant' || r === 'system' || r === 'tool') return r;
    return 'unknown';
  }
  function textFromMessageEl(el){
    if (!el) return '';
    var parts = [];
    var content = el.querySelector('.markdown, [data-message-content], .whitespace-pre-wrap, .prose, .text-message');
    var root = content || el;
    var nodes = root.querySelectorAll('p,li,pre,code,blockquote,h1,h2,h3,h4,h5,h6,div,span');
    if (nodes && nodes.length){
      for (var i=0;i<nodes.length;i++){
        var t = normSpace(nodes[i].innerText || nodes[i].textContent || '');
        if (t) parts.push(t);
      }
    } else {
      var t0 = normSpace(root.innerText || root.textContent || '');
      if (t0) parts.push(t0);
    }
    var joined = normSpace(parts.join('\n'));
    if (!joined){
      joined = normSpace(el.innerText || el.textContent || '');
    }
    return joined;
  }
  function getTime(el){
    var t = '';
    var timeEl = el.querySelector('time');
    if (timeEl){
      t = timeEl.getAttribute('datetime') || normSpace(timeEl.textContent || '');
    }
    if (!t){
      var cand = el.querySelector('[data-time],[data-timestamp],[aria-label*="time" i]');
      if (cand) t = cand.getAttribute('data-time') || cand.getAttribute('data-timestamp') || normSpace(cand.textContent || '');
    }
    return normSpace(t);
  }
  function getStatus(el){
    var s = '';
    if (el.querySelector('[data-state="loading"],[aria-busy="true"]')) s = 'loading';
    if (!s && el.querySelector('[data-error],[role="alert"]')) s = 'error';
    return normSpace(s);
  }
  function stableId(role, idx, text){
    var prefix = normSpace(text).slice(0, 32);
    return role + '-' + idx + '-' + prefix;
  }

  function extract(strategy){
    var container = null;
    if (strategy === 1){
      container = document.querySelector('#thread') || document.querySelector('main#main') || document.querySelector('main');
    } else {
      container = document.querySelector('main#main') || document.querySelector('main') || document.body;
    }

    var msgEls = [];
    var sel = [
      "[data-role='message']",
      "[data-message-role]",
      "[data-message-author-role]",
      "[data-message-id]",
      "article[data-testid^='conversation-turn-'] [data-message-author-role]",
      "article[data-testid^='conversation-turn-'] [role='listitem']",
      "[role='listitem'][data-message-author-role]",
      "[role='listitem'][data-message-id]"
    ].join(',');

    if (container) msgEls = Array.prototype.slice.call(container.querySelectorAll(sel));

    if (!msgEls.length){
      var turns = container ? container.querySelectorAll('article[data-testid^="conversation-turn-"]') : [];
      for (var i=0;i<turns.length;i++){
        var m = turns[i].querySelector('[data-message-author-role],[data-message-id],.text-message');
        if (m) msgEls.push(m);
      }
    }

    var items = [];
    var seen = new Set();
    for (var j=0;j<msgEls.length;j++){
      var el = msgEls[j];
      if (!el || seen.has(el)) continue;
      seen.add(el);

      var role = roleNorm(el.getAttribute('data-message-author-role') || el.getAttribute('data-message-role') || el.getAttribute('data-turn') || '');
      if (role === 'unknown'){
        var turn = el.closest('article[data-turn]');
        if (turn) role = roleNorm(turn.getAttribute('data-turn') || '');
      }

      var text = textFromMessageEl(el);
      if (!text) continue;

      var id = normSpace(el.getAttribute('data-message-id') || el.getAttribute('data-turn-id') || '');
      if (!id){
        var turn2 = el.closest('article[data-turn-id]');
        if (turn2) id = normSpace(turn2.getAttribute('data-turn-id') || '');
      }

      var time = getTime(el) || (el.closest('article') ? getTime(el.closest('article')) : '');
      var status = getStatus(el) || (el.closest('article') ? getStatus(el.closest('article')) : '');

      var idx = items.length;
      if (!id) id = stableId(role, idx, text);

      items.push({ id: String(id), role: String(role), text: String(text), time: String(time), status: String(status), index: idx });
    }

    return items;
  }

  var items = extract(1);
  if (!items.length) items = extract(2);

  if (items.length > limit) items = items.slice(items.length - limit);
  for (var k=0;k<items.length;k++) items[k].index = k;

  var cursor = items.length ? String(items[items.length-1].id || '') : '';
  return { action: 'getMessages', items: items, cursor: cursor };
}
